{
  "name": "@node/newton-sim",
  "version": "1.0.0",
  "description": "Interactive Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "main": "server.ts",
  "modnet": {
    "contentType": "science",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type SimulationType = 'pendulum' | 'projectile' | 'spring'

export type Vec2 = {
  x: number
  y: number
}

export type SimState = {
  time: number
  running: boolean
  speed: number
}

export type PendulumParams = {
  length: number
  gravity: number
  initialAngle: number
  damping: number
}

export type PendulumState = {
  angle: number
  angularVelocity: number
  angularAcceleration: number
  position: Vec2
}

export type ProjectileParams = {
  launchAngle: number
  initialVelocity: number
  gravity: number
}

export type ProjectileState = {
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
  trail: Vec2[]
  landed: boolean
}

export type SpringParams = {
  springConstant: number
  mass: number
  initialDisplacement: number
  damping: number
}

export type SpringState = {
  displacement: number
  velocity: number
  acceleration: number
}

export type SliderConfig = {
  id: string
  label: string
  min: number
  max: number
  step: number
  value: number
  unit: string
}

