  1→import type {
  2→  SimulationState,
  3→  SimulationType,
  4→  PendulumParams,
  5→  ProjectileParams,
  6→  SpringParams,
  7→} from './types'
  8→import {
  9→  createPendulumState,
 10→  stepPendulum,
 11→  createProjectileState,
 12→  stepProjectile,
 13→  createSpringState,
 14→  stepSpring,
 15→} from './physics'
 16→
 17→const DT = 1 / 60 // Physics timestep (60 Hz)
 18→const SUB_STEPS = 4 // Sub-stepping for accuracy
 19→
 20→export type SimulationEngine = {
 21→  getState: () => SimulationState
 22→  play: () => void
 23→  pause: () => void
 24→  reset: () => void
 25→  setSpeed: (speed: number) => void
 26→  setSimType: (type: SimulationType) => void
 27→  updateParam: (key: string, value: number) => void
 28→  tick: () => void
 29→}
 30→
 31→const defaultPendulumParams: PendulumParams = {
 32→  length: 1.5,
 33→  gravity: 9.81,
 34→  initialAngle: 30,
 35→  damping: 0,
 36→}
 37→
 38→const defaultProjectileParams: ProjectileParams = {
 39→  angle: 45,
 40→  initialVelocity: 20,
 41→  gravity: 9.81,
 42→}
 43→
 44→const defaultSpringParams: SpringParams = {
 45→  springConstant: 10,
 46→  mass: 1.0,
 47→  initialDisplacement: 0.5,
 48→  damping: 0,
 49→}
 50→
 51→export const createSimulation = (): SimulationEngine => {
 52→  const state: SimulationState = {
 53→    type: 'pendulum',
 54→    playback: 'stopped',
 55→    speed: 1,
 56→    pendulum: {
 57→      params: { ...defaultPendulumParams },
 58→      state: createPendulumState(defaultPendulumParams),
 59→    },
 60→    projectile: {
 61→      params: { ...defaultProjectileParams },
 62→      state: createProjectileState(defaultProjectileParams),
 63→    },
 64→    spring: {
 65→      params: { ...defaultSpringParams },
 66→      state: createSpringState(defaultSpringParams),
 67→    },
 68→  }
 69→
 70→  const getState = (): SimulationState => state
 71→
 72→  const play = () => {
 73→    state.playback = 'playing'
 74→  }
 75→
 76→  const pause = () => {
 77→    state.playback = 'paused'
 78→  }
 79→
 80→  const reset = () => {
 81→    state.playback = 'stopped'
 82→    state.pendulum.state = createPendulumState(state.pendulum.params)
 83→    state.projectile.state = createProjectileState(state.projectile.params)
 84→    state.spring.state = createSpringState(state.spring.params)
 85→  }
 86→
 87→  const setSpeed = (speed: number) => {
 88→    state.speed = Math.max(0.25, Math.min(4, speed))
 89→  }
 90→
 91→  const setSimType = (type: SimulationType) => {
 92→    state.type = type
 93→  }
 94→
 95→  const updateParam = (key: string, value: number) => {
 96→    const { type } = state
 97→    if (type === 'pendulum') {
 98→      const params = state.pendulum.params as Record<string, number>
 99→      if (key in params) {
100→        params[key] = value
101→        state.pendulum.state = createPendulumState(state.pendulum.params)
102→      }
103→    } else if (type === 'projectile') {
104→      const params = state.projectile.params as Record<string, number>
105→      if (key in params) {
106→        params[key] = value
107→        state.projectile.state = createProjectileState(state.projectile.params)
108→      }
109→    } else if (type === 'spring') {
110→      const params = state.spring.params as Record<string, number>
111→      if (key in params) {
112→        params[key] = value
113→        state.spring.state = createSpringState(state.spring.params)
114→      }
115→    }
116→    // Reset to stopped when params change so user sees initial state
117→    state.playback = 'stopped'
118→  }
119→
120→  const tick = () => {
121→    if (state.playback !== 'playing') return
122→
123→    const dt = (DT * state.speed) / SUB_STEPS
124→
125→    for (let i = 0; i < SUB_STEPS; i++) {
126→      if (state.type === 'pendulum') {
127→        state.pendulum.state = stepPendulum(state.pendulum.state, state.pendulum.params, dt)
128→      } else if (state.type === 'projectile') {
129→        state.projectile.state = stepProjectile(state.projectile.state, state.projectile.params, dt)
130→        if (state.projectile.state.landed) {
131→          state.playback = 'paused'
132→          break
133→        }
134→      } else if (state.type === 'spring') {
135→        state.spring.state = stepSpring(state.spring.state, state.spring.params, dt)
136→      }
137→    }
138→  }
139→
140→  return { getState, play, pause, reset, setSpeed, setSimType, updateParam, tick }
141→}
