  1→/**
  2→ * Client-side runtime for the Newton's Laws Simulator.
  3→ * Handles the animation loop, event delegation, and DOM updates.
  4→ * This script is inlined into the served HTML page.
  5→ */
  6→
  7→export const clientScript = `
  8→<script type="module">
  9→const DT = 1 / 60;
 10→const SUB_STEPS = 4;
 11→
 12→// ---- Physics Engine (inline for client) ----
 13→
 14→const pendulumDeriv = (theta, omega, g, L, b) => ({
 15→  dTheta: omega,
 16→  dOmega: -(g / L) * Math.sin(theta) - b * omega,
 17→});
 18→
 19→const rk4Pendulum = (theta, omega, g, L, b, dt) => {
 20→  const k1 = pendulumDeriv(theta, omega, g, L, b);
 21→  const k2 = pendulumDeriv(theta + dt/2*k1.dTheta, omega + dt/2*k1.dOmega, g, L, b);
 22→  const k3 = pendulumDeriv(theta + dt/2*k2.dTheta, omega + dt/2*k2.dOmega, g, L, b);
 23→  const k4 = pendulumDeriv(theta + dt*k3.dTheta, omega + dt*k3.dOmega, g, L, b);
 24→  return {
 25→    theta: theta + (dt/6)*(k1.dTheta + 2*k2.dTheta + 2*k3.dTheta + k4.dTheta),
 26→    omega: omega + (dt/6)*(k1.dOmega + 2*k2.dOmega + 2*k3.dOmega + k4.dOmega),
 27→  };
 28→};
 29→
 30→const springDeriv = (x, v, k, m, b) => ({
 31→  dx: v,
 32→  dv: -(k/m)*x - b*v,
 33→});
 34→
 35→const rk4Spring = (x, v, k, m, b, dt) => {
 36→  const k1 = springDeriv(x, v, k, m, b);
 37→  const k2 = springDeriv(x + dt/2*k1.dx, v + dt/2*k1.dv, k, m, b);
 38→  const k3 = springDeriv(x + dt/2*k2.dx, v + dt/2*k2.dv, k, m, b);
 39→  const k4 = springDeriv(x + dt*k3.dx, v + dt*k3.dv, k, m, b);
 40→  return {
 41→    x: x + (dt/6)*(k1.dx + 2*k2.dx + 2*k3.dx + k4.dx),
 42→    v: v + (dt/6)*(k1.dv + 2*k2.dv + 2*k3.dv + k4.dv),
 43→  };
 44→};
 45→
 46→// ---- State ----
 47→
 48→const state = {
 49→  type: 'pendulum',
 50→  playback: 'stopped',
 51→  speed: 1,
 52→  pendulum: {
 53→    params: { length: 1.5, gravity: 9.81, initialAngle: 30, damping: 0 },
 54→    theta: 30 * Math.PI / 180,
 55→    omega: 0,
 56→    time: 0,
 57→  },
 58→  projectile: {
 59→    params: { angle: 45, initialVelocity: 20, gravity: 9.81 },
 60→    time: 0,
 61→    trail: [],
 62→    landed: false,
 63→  },
 64→  spring: {
 65→    params: { springConstant: 10, mass: 1.0, initialDisplacement: 0.5, damping: 0 },
 66→    x: 0.5,
 67→    v: 0,
 68→    time: 0,
 69→  },
 70→};
 71→
 72→const resetSim = () => {
 73→  state.playback = 'stopped';
 74→  const p = state.pendulum;
 75→  p.theta = p.params.initialAngle * Math.PI / 180;
 76→  p.omega = 0;
 77→  p.time = 0;
 78→  const pr = state.projectile;
 79→  pr.time = 0;
 80→  pr.trail = [{x:0,y:0}];
 81→  pr.landed = false;
 82→  const s = state.spring;
 83→  s.x = s.params.initialDisplacement;
 84→  s.v = 0;
 85→  s.time = 0;
 86→};
 87→
 88→resetSim();
 89→
 90→// ---- Rendering helpers ----
 91→
 92→const fmt = (n, d=2) => Number.isFinite(n) ? n.toFixed(d) : '0.00';
 93→const CANVAS_W = 600, CANVAS_H = 400;
 94→const colors = {
 95→  bg:'#0f172a', panel:'#1e293b', border:'#334155',
 96→  accent:'#3b82f6', text:'#e2e8f0', textMuted:'#94a3b8',
 97→  rod:'#64748b', bob:'#f59e0b', trail:'#10b981',
 98→  proj:'#ef4444', spring:'#8b5cf6', mass:'#ec4899',
 99→  ground:'#475569', grid:'#1e293b', ke:'#f59e0b', pe:'#3b82f6',
100→};
101→
102→const svgNS = 'http://www.w3.org/2000/svg';
103→const el = (tag, attrs={}, ...ch) => {
104→  const isSvg = ['svg','line','circle','rect','text','path','polyline','defs','marker','g'].includes(tag);
105→  const e = isSvg ? document.createElementNS(svgNS, tag) : document.createElement(tag);
106→  for (const [k,v] of Object.entries(attrs)) e.setAttribute(k, String(v));
107→  ch.forEach(c => { if (typeof c === 'string') e.appendChild(document.createTextNode(c)); else if (c) e.appendChild(c); });
108→  return e;
109→};
110→
111→// ---- Canvas renderers ----
112→
113→const renderPendulumSVG = () => {
114→  const p = state.pendulum;
115→  const L = p.params.length;
116→  const g = p.params.gravity;
117→  const cx = CANVAS_W/2, cy = 60;
118→  const scale = 120 / L;
119→  const posX = L * Math.sin(p.theta);
120→  const posY = L * Math.cos(p.theta);
121→  const bobX = cx + posX * scale;
122→  const bobY = cy + posY * scale;
123→  const angAcc = -(g/L)*Math.sin(p.theta) - p.params.damping*p.omega;
124→  const linVel = Math.abs(p.omega * L);
125→  const linAcc = Math.abs(angAcc * L);
126→  const height = L*(1-Math.cos(p.theta));
127→  const ke = 0.5*linVel*linVel;
128→  const pe = g*height;
129→
130→  const svg = el('svg', {width:CANVAS_W, height:CANVAS_H, style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});
131→  for (let i=1;i<8;i++){const y=i*(CANVAS_H/8); svg.appendChild(el('line',{x1:0,y1:y,x2:CANVAS_W,y2:y,stroke:colors.grid,'stroke-width':1,'stroke-dasharray':'4,4'}));}
132→  svg.appendChild(el('circle',{cx,cy,r:5,fill:colors.ground}));
133→  svg.appendChild(el('line',{x1:cx,y1:cy,x2:cx,y2:cy+50,stroke:colors.textMuted,'stroke-width':1,'stroke-dasharray':'3,3'}));
134→  svg.appendChild(el('line',{x1:cx,y1:cy,x2:bobX,y2:bobY,stroke:colors.rod,'stroke-width':2}));
135→  svg.appendChild(el('circle',{cx:bobX,cy:bobY,r:16,fill:colors.bob,stroke:'#d97706','stroke-width':2}));
136→  svg.appendChild(el('text',{x:10,y:25,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'\\u03B8 = '+fmt(p.theta*180/Math.PI,1)+'\\u00B0'));
137→  svg.appendChild(el('text',{x:10,y:42,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(p.time,1)+'s'));
138→
139→  return { svg, values: {
140→    angle: fmt(p.theta*180/Math.PI,1)+'\\u00B0', angVel: fmt(p.omega,3)+' rad/s',
141→    posX: fmt(posX,3)+' m', posY: fmt(posY,3)+' m',
142→    vel: fmt(linVel,3)+' m/s', acc: fmt(linAcc,3)+' m/s\\u00B2',
143→    ke: fmt(ke,3)+' J', pe: fmt(pe,3)+' J',
144→  }};
145→};
146→
147→const renderProjectileSVG = () => {
148→  const pr = state.projectile;
149→  const a = pr.params.angle*Math.PI/180;
150→  const v0 = pr.params.initialVelocity;
151→  const g = pr.params.gravity;
152→  const t = pr.time;
153→  const maxRange = v0*v0*Math.sin(2*a)/g;
154→  const maxH = v0*v0*Math.sin(a)*Math.sin(a)/(2*g);
155→  const margin = 40;
156→  const plotW = CANVAS_W-2*margin, plotH = CANVAS_H-2*margin;
157→  const scale = Math.min(plotW/Math.max(maxRange*1.1,1), plotH/Math.max(maxH*1.3,1));
158→  const groundY = CANVAS_H-margin;
159→  const tx = x=>margin+x*scale, ty = y=>groundY-y*scale;
160→
161→  const x = v0*Math.cos(a)*t;
162→  const y = v0*Math.sin(a)*t-0.5*g*t*t;
163→  const vx = v0*Math.cos(a);
164→  const vy = v0*Math.sin(a)-g*t;
165→  const spd = Math.sqrt(vx*vx+vy*vy);
166→
167→  const svg = el('svg',{width:CANVAS_W,height:CANVAS_H,style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});
168→  svg.appendChild(el('line',{x1:margin,y1:groundY,x2:CANVAS_W-margin,y2:groundY,stroke:colors.ground,'stroke-width':2}));
169→  svg.appendChild(el('line',{x1:margin,y1:margin,x2:margin,y2:groundY,stroke:colors.ground,'stroke-width':1}));
170→  for(let i=0;i<5;i++){const yy=groundY-(i+1)*plotH/6; svg.appendChild(el('line',{x1:margin,y1:yy,x2:CANVAS_W-margin,y2:yy,stroke:colors.grid,'stroke-width':1,'stroke-dasharray':'4,4'}));}
171→
172→  if(pr.trail.length>1){
173→    const pts = pr.trail.map(p=>tx(p.x)+','+ty(p.y)).join(' ');
174→    svg.appendChild(el('polyline',{points:pts,fill:'none',stroke:colors.trail,'stroke-width':2,opacity:'0.7'}));
175→  }
176→
177→  const cy = Math.max(0,y);
178→  svg.appendChild(el('circle',{cx:tx(x),cy:ty(cy),r:8,fill:colors.proj,stroke:'#dc2626','stroke-width':2}));
179→  svg.appendChild(el('text',{x:10,y:20,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'Range: '+fmt(maxRange,1)+'m'));
180→  svg.appendChild(el('text',{x:10,y:37,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'Max H: '+fmt(maxH,1)+'m'));
181→  svg.appendChild(el('text',{x:10,y:54,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(t,1)+'s'));
182→
183→  return { svg, values: {
184→    posX: fmt(x,2)+' m', posY: fmt(Math.max(0,y),2)+' m',
185→    velX: fmt(vx,2)+' m/s', velY: fmt(pr.landed?0:vy,2)+' m/s',
186→    speed: fmt(pr.landed?0:spd,2)+' m/s', accY: fmt(-g,2)+' m/s\\u00B2',
187→    ke: fmt(0.5*spd*spd,2)+' J', pe: fmt(g*Math.max(0,y),2)+' J',
188→  }};
189→};
190→
191→const renderSpringSVG = () => {
192→  const s = state.spring;
193→  const k = s.params.springConstant;
194→  const m = s.params.mass;
195→  const anchorX = 80, anchorY = CANVAS_H/2;
196→  const eqX = CANVAS_W/2, scale = 150;
197→  const massX = eqX + s.x * scale;
198→  const mSize = 30;
199→  const acc = -(k/m)*s.x - s.params.damping*s.v;
200→  const keV = 0.5*m*s.v*s.v;
201→  const peV = 0.5*k*s.x*s.x;
202→  const maxE = 0.5*k*s.params.initialDisplacement*s.params.initialDisplacement;
203→
204→  const svg = el('svg',{width:CANVAS_W,height:CANVAS_H,style:'background:'+colors.bg+';border-radius:8px;border:1px solid '+colors.border});
205→  svg.appendChild(el('rect',{x:anchorX-5,y:anchorY-60,width:10,height:120,fill:colors.ground,rx:2}));
206→  for(let i=0;i<6;i++){const yy=anchorY-50+i*20; svg.appendChild(el('line',{x1:anchorX-5,y1:yy,x2:anchorX-15,y2:yy+10,stroke:colors.ground,'stroke-width':1}));}
207→  svg.appendChild(el('line',{x1:eqX,y1:anchorY-80,x2:eqX,y2:anchorY+80,stroke:colors.textMuted,'stroke-width':1,'stroke-dasharray':'4,4'}));
208→  svg.appendChild(el('text',{x:eqX-5,y:anchorY+95,fill:colors.textMuted,'font-size':10,'font-family':'monospace'},'x=0'));
209→
210→  // Spring path
211→  const numCoils = 12;
212→  const sStartX = anchorX+20, sEndX = massX-mSize/2;
213→  const cw = (sEndX-sStartX)/numCoils, ca = 15;
214→  let d = 'M '+sStartX+' '+anchorY;
215→  for(let i=0;i<numCoils;i++){
216→    const x1=sStartX+(i+0.25)*cw, x2=sStartX+(i+0.75)*cw, x3=sStartX+(i+1)*cw;
217→    const yOff=i%2===0?-ca:ca;
218→    d+=' L '+x1+' '+(anchorY+yOff)+' L '+x2+' '+(anchorY-yOff)+' L '+x3+' '+anchorY;
219→  }
220→  svg.appendChild(el('path',{d,fill:'none',stroke:colors.spring,'stroke-width':2.5,'stroke-linecap':'round','stroke-linejoin':'round'}));
221→  svg.appendChild(el('rect',{x:massX-mSize/2,y:anchorY-mSize/2,width:mSize,height:mSize,fill:colors.mass,stroke:'#db2777','stroke-width':2,rx:4}));
222→  svg.appendChild(el('text',{x:massX-5,y:anchorY+4,fill:'#fff','font-size':11,'font-family':'monospace','font-weight':'bold'},'m'));
223→  svg.appendChild(el('line',{x1:anchorX,y1:anchorY+mSize/2+5,x2:CANVAS_W-40,y2:anchorY+mSize/2+5,stroke:colors.ground,'stroke-width':1,'stroke-dasharray':'6,3'}));
224→
225→  // Energy bars
226→  const keH = maxE>0?(keV/maxE)*80:0, peH = maxE>0?(peV/maxE)*80:0;
227→  svg.appendChild(el('rect',{x:CANVAS_W-60,y:CANVAS_H-30-keH,width:18,height:Math.max(keH,1),fill:colors.ke,rx:2}));
228→  svg.appendChild(el('text',{x:CANVAS_W-56,y:CANVAS_H-12,fill:colors.ke,'font-size':9,'font-family':'monospace'},'KE'));
229→  svg.appendChild(el('rect',{x:CANVAS_W-35,y:CANVAS_H-30-peH,width:18,height:Math.max(peH,1),fill:colors.pe,rx:2}));
230→  svg.appendChild(el('text',{x:CANVAS_W-31,y:CANVAS_H-12,fill:colors.pe,'font-size':9,'font-family':'monospace'},'PE'));
231→
232→  svg.appendChild(el('text',{x:10,y:25,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'x = '+fmt(s.x,3)+'m'));
233→  svg.appendChild(el('text',{x:10,y:42,fill:colors.textMuted,'font-size':12,'font-family':'monospace'},'t = '+fmt(s.time,1)+'s'));
234→
235→  return { svg, values: {
236→    disp: fmt(s.x,3)+' m', vel: fmt(s.v,3)+' m/s',
237→    acc: fmt(acc,3)+' m/s\\u00B2', time: fmt(s.time,2)+' s',
238→    ke: fmt(keV,4)+' J', pe: fmt(peV,4)+' J',
239→  }};
240→};
241→
242→// ---- DOM update ----
243→
244→const canvasContainer = document.getElementById('sim-canvas');
245→const valuesContainer = document.getElementById('sim-values');
246→
247→const valueLabels = {
248→  pendulum: [['Angle','angle'],['Angular Vel','angVel'],['Position X','posX'],['Position Y','posY'],['Velocity','vel'],['Acceleration','acc'],['Kinetic E','ke'],['Potential E','pe']],
249→  projectile: [['Position X','posX'],['Position Y','posY'],['Velocity X','velX'],['Velocity Y','velY'],['Speed','speed'],['Accel Y','accY'],['Kinetic E','ke'],['Potential E','pe']],
250→  spring: [['Displacement','disp'],['Velocity','vel'],['Acceleration','acc'],['Time','time'],['Kinetic E','ke'],['Potential E','pe']],
251→};
252→
253→const updateValues = (vals) => {
254→  const labels = valueLabels[state.type];
255→  let html = '';
256→  labels.forEach(([label, key]) => {
257→    const isEnergy = key === 'ke' || key === 'pe';
258→    const color = key === 'ke' ? colors.ke : key === 'pe' ? colors.pe : colors.text;
259→    html += '<div style="display:flex;justify-content:space-between;align-items:center">';
260→    html += '<span style="color:'+colors.textMuted+';font-size:11px">'+label+'</span>';
261→    html += '<span style="color:'+color+';font-size:12px;font-family:monospace;font-weight:600">'+vals[key]+'</span>';
262→    html += '</div>';
263→  });
264→  valuesContainer.innerHTML = html;
265→};
266→
267→const render = () => {
268→  let result;
269→  if (state.type === 'pendulum') result = renderPendulumSVG();
270→  else if (state.type === 'projectile') result = renderProjectileSVG();
271→  else result = renderSpringSVG();
272→  canvasContainer.innerHTML = '';
273→  canvasContainer.appendChild(result.svg);
274→  updateValues(result.values);
275→};
276→
277→// ---- Physics tick ----
278→
279→const tick = () => {
280→  if (state.playback !== 'playing') return;
281→  const dt = (DT * state.speed) / SUB_STEPS;
282→  for (let i = 0; i < SUB_STEPS; i++) {
283→    if (state.type === 'pendulum') {
284→      const p = state.pendulum;
285→      const next = rk4Pendulum(p.theta, p.omega, p.params.gravity, p.params.length, p.params.damping, dt);
286→      p.theta = next.theta;
287→      p.omega = next.omega;
288→      p.time += dt;
289→    } else if (state.type === 'projectile') {
290→      const pr = state.projectile;
291→      if (pr.landed) { state.playback = 'paused'; break; }
292→      pr.time += dt;
293→      const a = pr.params.angle*Math.PI/180;
294→      const v0 = pr.params.initialVelocity;
295→      const g = pr.params.gravity;
296→      const x = v0*Math.cos(a)*pr.time;
297→      const y = v0*Math.sin(a)*pr.time - 0.5*g*pr.time*pr.time;
298→      if (y <= 0 && pr.time > 0.05) { pr.landed = true; state.playback = 'paused'; }
299→      pr.trail.push({x, y: Math.max(0,y)});
300→      if (pr.trail.length > 500) pr.trail = pr.trail.slice(-500);
301→    } else {
302→      const s = state.spring;
303→      const next = rk4Spring(s.x, s.v, s.params.springConstant, s.params.mass, s.params.damping, dt);
304→      s.x = next.x;
305→      s.v = next.v;
306→      s.time += dt;
307→    }
308→  }
309→};
310→
311→// ---- Animation loop ----
312→
313→let animId = null;
314→const loop = () => {
315→  tick();
316→  render();
317→  animId = requestAnimationFrame(loop);
318→};
319→loop();
