370→    {id:'mass',label:'Mass',min:0.5,max:10,step:0.5,unit:'kg',key:'mass'},
371→    {id:'initialDisplacement',label:'Init Displ',min:0.1,max:1,step:0.05,unit:'m',key:'initialDisplacement'},
372→  ],
