390→    html += '<input type="range" id="slider-'+c.id+'" min="'+c.min+'" max="'+c.max+'" step="'+c.step+'" value="'+val+'" data-param="'+c.key+'" style="flex:1;accent-color:'+colors.accent+'">';
391→    html += '<span id="val-'+c.id+'" style="color:'+colors.text+';font-size:12px;min-width:60px;text-align:right">'+fmt(val, c.step<1?2:1)+' '+c.unit+'</span>';
392→    html += '</div>';
