 364→              h('h3', { style: styleToStr(styles.cardTitle) }, 'Real-Time Values'),
 365→              h('div', { style: styleToStr(styles.readout) },
 366→                renderReadoutItem('r-pos', 'Position', '0.00 m'),
 367→                renderReadoutItem('r-vel', 'Velocity', '0.00 m/s'),
 368→                renderReadoutItem('r-acc', 'Acceleration', '0.00 m/s\u00B2'),
 369→                renderReadoutItem('r-energy', 'Energy', '0.00 J'),
 370→                h('div', { style: styleToStr(styles.timeDisplay) },
 371→                  h('div', { style: styleToStr(styles.readoutLabel) }, 'Time'),
 372→                  h('div', { style: styleToStr(styles.readoutValue), id: 'r-time', 'p-target': 'r-time' }, '0.00 s'),
 373→                ),
 374→              ),
 375→            ),
 376→          ),
 377→        ),
 378→      ),
 379→      // Client-side simulation script
 380→      h('script', {}, clientScript()),
 381→    ),
 382→  )
 383→
 384→  const ssr = createSSR()
 385→  return ssr(page)
 386→}
 387→
 388→const clientScript = (): string => `
 389→(function() {
 390→  const DEG = Math.PI / 180;
 391→  const canvas = document.getElementById('sim-canvas');
 392→  const ctx = canvas.getContext('2d');
 393→  const dpr = window.devicePixelRatio || 1;
 394→
 395→  // Hi-DPI setup
 396→  const rect = canvas.getBoundingClientRect();
 397→  canvas.width = rect.width * dpr;
 398→  canvas.height = rect.height * dpr;
 399→  ctx.scale(dpr, dpr);
 400→  const W = rect.width;
 401→  const H = rect.height;
 402→
 403→  const colors = {
 404→    pendulum: '#4f8ff7',
 405→    projectile: '#34d399',
 406→    spring: '#fbbf24',
 407→    grid: '#1e2130',
 408→    axis: '#2a2d3a',
 409→    text: '#8b8fa3',
 410→    trail: '#4f8ff733',
 411→  };
 412→
 413→  let activeSim = 'pendulum';
 414→  let playing = false;
 415→  let speed = 1;
 416→  let lastFrame = 0;
 417→
 418→  // Pendulum state
 419→  let pend = { L: 2, g: 9.81, angle0: 30, theta: 0, omega: 0, time: 0, trail: [] };
 420→  // Projectile state
 421→  let proj = { angle: 45, v0: 20, g: 9.81, time: 0, landed: false, trail: [] };
 422→  // Spring state
 423→  let spr = { k: 10, m: 1, x0: 1, time: 0, trail: [] };
 424→
 425→  const resetPendulum = () => {
 426→    pend.theta = pend.angle0 * DEG;
 427→    pend.omega = 0;
 428→    pend.time = 0;
 429→    pend.trail = [];
 430→  };
 431→
 432→  const resetProjectile = () => {
 433→    proj.time = 0;
 434→    proj.landed = false;
 435→    proj.trail = [{ x: 0, y: 0 }];
 436→  };
 437→
 438→  const resetSpring = () => {
 439→    spr.time = 0;
 440→    spr.trail = [];
 441→  };
 442→
 443→  const resetAll = () => { resetPendulum(); resetProjectile(); resetSpring(); };
 444→
 445→  // --- Physics step functions ---
 446→
 447→  const stepPend = (dt) => {
 448→    const gL = pend.g / pend.L;
 449→    const steps = 4;
 450→    const h = dt / steps;
 451→    for (let i = 0; i < steps; i++) {
 452→      const k1t = pend.omega;
 453→      const k1o = -gL * Math.sin(pend.theta);
 454→      const k2t = pend.omega + 0.5 * h * k1o;
 455→      const k2o = -gL * Math.sin(pend.theta + 0.5 * h * k1t);
 456→      const k3t = pend.omega + 0.5 * h * k2o;
 457→      const k3o = -gL * Math.sin(pend.theta + 0.5 * h * k2t);
 458→      const k4t = pend.omega + h * k3o;
 459→      const k4o = -gL * Math.sin(pend.theta + h * k3t);
 460→      pend.theta += (h / 6) * (k1t + 2*k2t + 2*k3t + k4t);
 461→      pend.omega += (h / 6) * (k1o + 2*k2o + 2*k3o + k4o);
 462→    }
 463→    pend.time += dt;
 464→    const x = pend.L * Math.sin(pend.theta);
 465→    const y = -pend.L * Math.cos(pend.theta);
 466→    pend.trail.push({ x, y });
 467→    if (pend.trail.length > 300) pend.trail.shift();
 468→  };
 469→
 470→  const getProj = (t) => {
 471→    const ar = proj.angle * DEG;
 472→    const vx = proj.v0 * Math.cos(ar);
 473→    const vy = proj.v0 * Math.sin(ar);
 474→    return {
 475→      x: vx * t,
 476→      y: vy * t - 0.5 * proj.g * t * t,
 477→      vx,
 478→      vy: vy - proj.g * t,
 479→    };
 480→  };
 481→
 482→  const stepProj = (dt) => {
 483→    if (proj.landed) return;
 484→    proj.time += dt;
 485→    const p = getProj(proj.time);
 486→    if (p.y <= 0 && proj.time > 0.05) {
 487→      const ar = proj.angle * DEG;
 488→      const vy = proj.v0 * Math.sin(ar);
 489→      proj.time = (2 * vy) / proj.g;
 490→      proj.landed = true;
 491→      const pf = getProj(proj.time);
 492→      proj.trail.push({ x: pf.x, y: 0 });
 493→    } else {
 494→      proj.trail.push({ x: p.x, y: p.y });
 495→    }
 496→  };
 497→
 498→  const stepSpr = (dt) => {
 499→    spr.time += dt;
 500→    spr.trail.push({ t: spr.time, x: spr.x0 * Math.cos(Math.sqrt(spr.k / spr.m) * spr.time) });
 501→    if (spr.trail.length > 500) spr.trail.shift();
 502→  };
 503→
 504→  // --- Drawing ---
 505→
 506→  const drawGrid = (ox, oy, scaleX, scaleY, labelX, labelY) => {
 507→    ctx.strokeStyle = colors.grid;
 508→    ctx.lineWidth = 1;
 509→    for (let i = -20; i <= 20; i++) {
 510→      const gx = ox + i * scaleX;
 511→      if (gx >= 0 && gx <= W) {
 512→        ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, H); ctx.stroke();
 513→      }
 514→      const gy = oy + i * scaleY;
 515→      if (gy >= 0 && gy <= H) {
 516→        ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(W, gy); ctx.stroke();
 517→      }
 518→    }
 519→    ctx.strokeStyle = colors.axis;
 520→    ctx.lineWidth = 1.5;
 521→    ctx.beginPath(); ctx.moveTo(0, oy); ctx.lineTo(W, oy); ctx.stroke();
 522→    ctx.beginPath(); ctx.moveTo(ox, 0); ctx.lineTo(ox, H); ctx.stroke();
 523→  };
 524→
 525→  const drawPendulum = () => {
 526→    const ox = W / 2;
 527→    const oy = 80;
 528→    const scale = Math.min(180, (H - 120) / (pend.L * 1.2));
 529→
 530→    // Draw faint grid
 531→    ctx.strokeStyle = colors.grid;
 532→    ctx.lineWidth = 0.5;
 533→    for (let i = 0; i < 10; i++) {
 534→      ctx.beginPath();
 535→      ctx.arc(ox, oy, (i + 1) * scale * 0.5, 0, Math.PI * 2);
 536→      ctx.stroke();
 537→    }
 538→
 539→    // Trail (angle vs time)
 540→    if (pend.trail.length > 1) {
 541→      ctx.strokeStyle = colors.trail;
 542→      ctx.lineWidth = 1.5;
 543→      ctx.beginPath();
 544→      pend.trail.forEach((p, i) => {
 545→        const px = ox + p.x * scale;
 546→        const py = oy - p.y * scale;
 547→        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
 548→      });
 549→      ctx.stroke();
 550→    }
 551→
 552→    const bx = ox + pend.L * Math.sin(pend.theta) * scale;
 553→    const by = oy + pend.L * Math.cos(pend.theta) * scale;
 554→
 555→    // Rod
 556→    ctx.strokeStyle = '#556';
 557→    ctx.lineWidth = 2;
 558→    ctx.beginPath();
 559→    ctx.moveTo(ox, oy);
 560→    ctx.lineTo(bx, by);
 561→    ctx.stroke();
 562→
 563→    // Pivot
 564→    ctx.fillStyle = '#888';
 565→    ctx.beginPath();
 566→    ctx.arc(ox, oy, 5, 0, Math.PI * 2);
 567→    ctx.fill();
 568→
 569→    // Bob
 570→    const grad = ctx.createRadialGradient(bx - 3, by - 3, 2, bx, by, 18);
 571→    grad.addColorStop(0, '#7ab4ff');
 572→    grad.addColorStop(1, colors.pendulum);
 573→    ctx.fillStyle = grad;
 574→    ctx.beginPath();
 575→    ctx.arc(bx, by, 16, 0, Math.PI * 2);
 576→    ctx.fill();
 577→
 578→    ctx.shadowColor = colors.pendulum;
 579→    ctx.shadowBlur = 12;
 580→    ctx.beginPath();
 581→    ctx.arc(bx, by, 16, 0, Math.PI * 2);
 582→    ctx.fill();
 583→    ctx.shadowBlur = 0;
 584→
 585→    // Labels
 586→    ctx.fillStyle = colors.text;
 587→    ctx.font = '12px Inter, sans-serif';
 588→    ctx.textAlign = 'left';
 589→    ctx.fillText('L = ' + pend.L.toFixed(1) + ' m', 20, 30);
 590→    ctx.fillText('g = ' + pend.g.toFixed(1) + ' m/s\\u00B2', 20, 48);
 591→    ctx.fillText('\\u03B8 = ' + (pend.theta / DEG).toFixed(1) + '\\u00B0', 20, 66);
 592→  };
 593→
 594→  const drawProjectile = () => {
 595→    const ox = 60;
 596→    const oy = H - 60;
 597→    const ar = proj.angle * DEG;
 598→    const v0y = proj.v0 * Math.sin(ar);
 599→    const v0x = proj.v0 * Math.cos(ar);
 600→    const maxH = (v0y * v0y) / (2 * proj.g);
 601→    const range = (proj.v0 * proj.v0 * Math.sin(2 * ar)) / proj.g;
 602→
 603→    const scaleX = Math.min((W - 120) / (range * 1.1), 80);
 604→    const scaleY = Math.min((H - 120) / (maxH * 1.3), 80);
 605→    const sc = Math.min(scaleX, scaleY);
 606→
 607→    drawGrid(ox, oy, sc * (range / 5), -sc * (maxH / 4), '', '');
 608→
 609→    // Trajectory trail
 610→    if (proj.trail.length > 1) {
 611→      ctx.strokeStyle = colors.projectile;
 612→      ctx.lineWidth = 2.5;
 613→      ctx.setLineDash([]);
 614→      ctx.beginPath();
 615→      proj.trail.forEach((p, i) => {
 616→        const px = ox + p.x * sc;
 617→        const py = oy - p.y * sc;
 618→        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
 619→      });
 620→      ctx.stroke();
 621→
 622→      // Ghost full path
 623→      ctx.strokeStyle = colors.projectile + '33';
 624→      ctx.lineWidth = 1;
 625→      ctx.setLineDash([4, 4]);
 626→      ctx.beginPath();
 627→      const tTotal = (2 * v0y) / proj.g;
 628→      for (let t = 0; t <= tTotal; t += tTotal / 100) {
 629→        const px = ox + v0x * t * sc;
 630→        const py = oy - (v0y * t - 0.5 * proj.g * t * t) * sc;
 631→        t === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
 632→      }
 633→      ctx.stroke();
 634→      ctx.setLineDash([]);
 635→    }
 636→
 637→    // Current position dot
 638→    const cp = getProj(proj.time);
 639→    const cpx = ox + cp.x * sc;
 640→    const cpy = oy - Math.max(0, cp.y) * sc;
 641→    const grad = ctx.createRadialGradient(cpx - 2, cpy - 2, 1, cpx, cpy, 12);
 642→    grad.addColorStop(0, '#6ee7b7');
 643→    grad.addColorStop(1, colors.projectile);
 644→    ctx.fillStyle = grad;
 645→    ctx.beginPath();
 646→    ctx.arc(cpx, cpy, 10, 0, Math.PI * 2);
 647→    ctx.fill();
 648→    ctx.shadowColor = colors.projectile;
 649→    ctx.shadowBlur = 10;
 650→    ctx.fill();
 651→    ctx.shadowBlur = 0;
 652→
 653→    // Velocity arrow
 654→    if (!proj.landed) {
 655→      const arrScale = 2;
 656→      ctx.strokeStyle = '#f87171';
 657→      ctx.lineWidth = 2;
 658→      ctx.beginPath();
 659→      ctx.moveTo(cpx, cpy);
 660→      ctx.lineTo(cpx + cp.vx * arrScale, cpy - cp.vy * arrScale);
 661→      ctx.stroke();
 662→      const angle = Math.atan2(-cp.vy, cp.vx);
 663→      ctx.fillStyle = '#f87171';
 664→      ctx.beginPath();
 665→      ctx.moveTo(cpx + cp.vx * arrScale, cpy - cp.vy * arrScale);
 666→      ctx.lineTo(cpx + cp.vx * arrScale - 8 * Math.cos(angle - 0.4), cpy - cp.vy * arrScale - 8 * Math.sin(angle - 0.4));
 667→      ctx.lineTo(cpx + cp.vx * arrScale - 8 * Math.cos(angle + 0.4), cpy - cp.vy * arrScale - 8 * Math.sin(angle + 0.4));
 668→      ctx.closePath();
 669→      ctx.fill();
 670→    }
 671→
 672→    // Labels
 673→    ctx.fillStyle = colors.text;
 674→    ctx.font = '12px Inter, sans-serif';
 675→    ctx.textAlign = 'left';
 676→    ctx.fillText('Range: ' + range.toFixed(1) + ' m', 20, 30);
 677→    ctx.fillText('Max Height: ' + maxH.toFixed(1) + ' m', 20, 48);
 678→    ctx.fillText('v\\u2080 = ' + proj.v0 + ' m/s at ' + proj.angle + '\\u00B0', 20, 66);
 679→  };
 680→
 681→  const drawSpring = () => {
 682→    const ox = W / 2;
 683→    const oy = H / 2;
 684→    const omega = Math.sqrt(spr.k / spr.m);
 685→    const x = spr.x0 * Math.cos(omega * spr.time);
 686→    const scale = 120;
 687→
 688→    // Draw equilibrium line
 689→    ctx.strokeStyle = colors.axis;
 690→    ctx.lineWidth = 1;
 691→    ctx.setLineDash([5, 5]);
 692→    ctx.beginPath();
 693→    ctx.moveTo(ox, 100);
 694→    ctx.lineTo(ox, H - 40);
 695→    ctx.stroke();
 696→    ctx.setLineDash([]);
 697→
 698→    // Wall
 699→    ctx.fillStyle = '#2a2d3a';
 700→    ctx.fillRect(60, oy - 60, 12, 120);
 701→    ctx.strokeStyle = '#556';
 702→    ctx.lineWidth = 2;
 703→    for (let i = 0; i < 6; i++) {
 704→      ctx.beginPath();
 705→      ctx.moveTo(60, oy - 50 + i * 20);
 706→      ctx.lineTo(48, oy - 40 + i * 20);
 707→      ctx.stroke();
 708→    }
 709→
 710→    // Spring coils
 711→    const massX = ox + x * scale;
 712→    const springStart = 72;
 713→    const coils = 12;
 714→    const springLen = massX - springStart;
 715→    const coilW = springLen / coils;
 716→    const amplitude = 16;
 717→
 718→    ctx.strokeStyle = colors.spring;
 719→    ctx.lineWidth = 2.5;
 720→    ctx.beginPath();
 721→    ctx.moveTo(springStart, oy);
 722→    for (let i = 0; i <= coils; i++) {
 723→      const cx = springStart + i * coilW;
 724→      const cy = i % 2 === 0 ? oy - amplitude : oy + amplitude;
 725→      if (i === 0 || i === coils) {
 726→        ctx.lineTo(cx, oy);
 727→      } else {
 728→        ctx.lineTo(cx, cy);
 729→      }
 730→    }
 731→    ctx.stroke();
 732→
 733→    // Mass block
 734→    const blockW = 50;
 735→    const blockH = 50;
 736→    const grad = ctx.createLinearGradient(massX, oy - blockH/2, massX + blockW, oy + blockH/2);
 737→    grad.addColorStop(0, '#fde68a');
 738→    grad.addColorStop(1, colors.spring);
 739→    ctx.fillStyle = grad;
 740→    ctx.beginPath();
 741→    ctx.roundRect(massX - blockW/2, oy - blockH/2, blockW, blockH, 8);
 742→    ctx.fill();
 743→    ctx.shadowColor = colors.spring;
 744→    ctx.shadowBlur = 10;
 745→    ctx.fill();
 746→    ctx.shadowBlur = 0;
 747→
 748→    ctx.fillStyle = '#000';
 749→    ctx.font = 'bold 14px Inter, sans-serif';
 750→    ctx.textAlign = 'center';
 751→    ctx.fillText(spr.m.toFixed(1) + ' kg', massX, oy + 5);
 752→
 753→    // Displacement arrow
 754→    if (Math.abs(x) > 0.02) {
 755→      ctx.strokeStyle = '#f87171';
 756→      ctx.lineWidth = 2;
 757→      ctx.beginPath();
 758→      ctx.moveTo(ox, oy + 50);
 759→      ctx.lineTo(massX, oy + 50);
 760→      ctx.stroke();
 761→      const dir = x > 0 ? 1 : -1;
 762→      ctx.fillStyle = '#f87171';
 763→      ctx.beginPath();
 764→      ctx.moveTo(massX, oy + 50);
 765→      ctx.lineTo(massX - dir * 8, oy + 44);
 766→      ctx.lineTo(massX - dir * 8, oy + 56);
 767→      ctx.closePath();
 768→      ctx.fill();
 769→      ctx.fillStyle = colors.text;
 770→      ctx.font = '12px Inter, sans-serif';
 771→      ctx.fillText('x = ' + x.toFixed(3) + ' m', (ox + massX) / 2, oy + 72);
 772→    }
 773→
 774→    // Displacement-time graph
 775→    const graphX = 60;
 776→    const graphY = H - 130;
 777→    const graphW = W - 120;
 778→    const graphH = 90;
 779→
 780→    ctx.strokeStyle = colors.border;
 781→    ctx.lineWidth = 1;
 782→    ctx.strokeRect(graphX, graphY, graphW, graphH);
 783→    ctx.strokeStyle = colors.axis;
 784→    ctx.beginPath();
 785→    ctx.moveTo(graphX, graphY + graphH / 2);
 786→    ctx.lineTo(graphX + graphW, graphY + graphH / 2);
 787→    ctx.stroke();
 788→
 789→    ctx.fillStyle = colors.text;
 790→    ctx.font = '10px Inter, sans-serif';
 791→    ctx.textAlign = 'left';
 792→    ctx.fillText('x(t)', graphX + 4, graphY + 14);
 793→
 794→    if (spr.trail.length > 1) {
 795→      const tMax = Math.max(spr.trail[spr.trail.length - 1].t, 5);
 796→      const tMin = spr.trail[0].t;
 797→      ctx.strokeStyle = colors.spring;
 798→      ctx.lineWidth = 2;
 799→      ctx.beginPath();
 800→      spr.trail.forEach((p, i) => {
 801→        const px = graphX + ((p.t - tMin) / (tMax - tMin)) * graphW;
 802→        const py = graphY + graphH / 2 - (p.x / spr.x0) * (graphH / 2 - 8);
 803→        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
 804→      });
 805→      ctx.stroke();
 806→    }
 807→
 808→    // Labels
 809→    ctx.fillStyle = colors.text;
 810→    ctx.font = '12px Inter, sans-serif';
 811→    ctx.textAlign = 'left';
 812→    ctx.fillText('k = ' + spr.k + ' N/m', 20, 30);
 813→    ctx.fillText('m = ' + spr.m.toFixed(1) + ' kg', 20, 48);
 814→    ctx.fillText('\\u03C9 = ' + omega.toFixed(2) + ' rad/s', 20, 66);
 815→    ctx.fillText('T = ' + (2 * Math.PI / omega).toFixed(2) + ' s', 20, 84);
 816→  };
 817→
 818→  const draw = () => {
 819→    ctx.clearRect(0, 0, W, H);
 820→    ctx.fillStyle = '#141720';
 821→    ctx.fillRect(0, 0, W, H);
 822→
 823→    if (activeSim === 'pendulum') drawPendulum();
 824→    else if (activeSim === 'projectile') drawProjectile();
 825→    else drawSpring();
 826→  };
 827→
 828→  // --- Readouts ---
 829→
 830→  const updateReadouts = () => {
 831→    const fmt = (n) => n.toFixed(2);
 832→    const el = (id) => document.getElementById(id);
 833→    if (!el('r-pos')) return;
 834→
 835→    if (activeSim === 'pendulum') {
 836→      const x = pend.L * Math.sin(pend.theta);
 837→      const y = -pend.L * Math.cos(pend.theta);
 838→      const v = pend.L * Math.abs(pend.omega);
 839→      const a = pend.L * Math.abs(-pend.g / pend.L * Math.sin(pend.theta));
 840→      const pe = pend.g * pend.L * (1 - Math.cos(pend.theta));
 841→      const ke = 0.5 * pend.L * pend.L * pend.omega * pend.omega;
 842→      el('r-pos').textContent = '(' + fmt(x) + ', ' + fmt(y) + ') m';
 843→      el('r-vel').textContent = fmt(v) + ' m/s';
 844→      el('r-acc').textContent = fmt(a) + ' m/s\\u00B2';
 845→      el('r-energy').textContent = fmt(pe + ke) + ' J';
 846→      el('r-time').textContent = fmt(pend.time) + ' s';
 847→    } else if (activeSim === 'projectile') {
 848→      const p = getProj(proj.time);
 849→      const spd = Math.sqrt(p.vx * p.vx + p.vy * p.vy);
 850→      const ke = 0.5 * spd * spd;
 851→      const pe = proj.g * Math.max(0, p.y);
 852→      el('r-pos').textContent = '(' + fmt(p.x) + ', ' + fmt(Math.max(0, p.y)) + ') m';
 853→      el('r-vel').textContent = '(' + fmt(p.vx) + ', ' + fmt(p.vy) + ') m/s';
 854→      el('r-acc').textContent = '(0, -' + fmt(proj.g) + ') m/s\\u00B2';
 855→      el('r-energy').textContent = fmt(ke + pe) + ' J';
 856→      el('r-time').textContent = fmt(proj.time) + ' s';
 857→    } else {
 858→      const omega = Math.sqrt(spr.k / spr.m);
 859→      const x = spr.x0 * Math.cos(omega * spr.time);
 860→      const v = -spr.x0 * omega * Math.sin(omega * spr.time);
 861→      const a = -spr.x0 * omega * omega * Math.cos(omega * spr.time);
 862→      const pe = 0.5 * spr.k * x * x;
 863→      const ke = 0.5 * spr.m * v * v;
 864→      el('r-pos').textContent = fmt(x) + ' m';
 865→      el('r-vel').textContent = fmt(v) + ' m/s';
 866→      el('r-acc').textContent = fmt(a) + ' m/s\\u00B2';
 867→      el('r-energy').textContent = fmt(pe + ke) + ' J';
 868→      el('r-time').textContent = fmt(spr.time) + ' s';
 869→    }
 870→  };
 871→
 872→  // --- Animation loop ---
 873→
 874→  const loop = (ts) => {
 875→    if (!lastFrame) lastFrame = ts;
 876→    const rawDt = (ts - lastFrame) / 1000;
 877→    lastFrame = ts;
 878→
