325→      const res = await fetch('/tick');
326→      if (res.ok) {
327→        const html = await res.text();
328→        if (html.trim()) document.body.innerHTML = html;
329→      }
330→    };
331→    setInterval(tickLoop, TICK_INTERVAL);
332→  </script>
333→</body>
334→</html>`
335→}
336→
337→const main = async () => {
338→  let state = await createInitialState()
339→
340→  const server = Bun.serve({
341→    port: 3000,
342→    fetch: async (req) => {
343→      const url = new URL(req.url)
344→
345→      if (url.pathname === '/tick') {
346→        state = tick(state)
347→        if (!state.simulation.isPlaying) {
348→          return new Response('', { headers: { 'Content-Type': 'text/html' } })
349→        }
350→        const ssr = createSSR()
351→        const body = ssr(render(state))
352→        return new Response(body, { headers: { 'Content-Type': 'text/html' } })
353→      }
354→
355→      if (url.pathname === '/event') {
356→        const action = url.searchParams.get('action') ?? ''
357→
358→        if (action.startsWith('tab=')) {
359→          const sim = action.replace('tab=', '') as SimulationType
360→          state = handleEvent(state, { type: 'tab', sim })
361→        } else if (action === 'toggle-play') {
362→          state = handleEvent(state, { type: 'toggle-play' })
363→        } else if (action === 'reset') {
364→          state = handleEvent(state, { type: 'reset' })
365→        } else if (action.startsWith('set-speed=')) {
366→          const speed = parseFloat(action.replace('set-speed=', ''))
367→          state = handleEvent(state, { type: 'set-speed', speed })
368→        } else if (action === 'param') {
369→          const key = url.searchParams.get('key') ?? ''
370→          const value = parseFloat(url.searchParams.get('value') ?? '0')
371→          state = handleEvent(state, { type: 'param', key, value })
372→        }
373→
374→        await saveState(state)
375→        const ssr = createSSR()
376→        const body = ssr(render(state))
377→        return new Response(body, { headers: { 'Content-Type': 'text/html' } })
378→      }
379→
380→      // Default: full page
381→      const html = await renderToHtml(state)
382→      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
383→    },
384→  })
385→
386→  console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
387→}
388→
389→export {
390→  createInitialState,
391→  tick,
392→  handleEvent,
393→  render,
394→  main,
395→}
