 1→import type { ProjectileParams, ProjectileState, Vector2D } from '../types'
 2→
 3→const DEG_TO_RAD = Math.PI / 180
 4→
 5→export const createProjectileState = (params: ProjectileParams): ProjectileState => {
 6→  const angleRad = params.angle * DEG_TO_RAD
 7→  return {
 8→    position: { x: 0, y: 0 },
 9→    velocity: {
10→      x: params.initialVelocity * Math.cos(angleRad),
11→      y: params.initialVelocity * Math.sin(angleRad),
12→    },
13→    acceleration: { x: 0, y: -params.gravity },
14→    trajectory: [{ x: 0, y: 0 }],
15→    landed: false,
16→  }
17→}
18→
19→export const updateProjectile = (
20→  state: ProjectileState,
21→  params: ProjectileParams,
22→  dt: number,
23→): ProjectileState => {
24→  if (state.landed) return state
25→
26→  const newVelocity: Vector2D = {
27→    x: state.velocity.x,
28→    y: state.velocity.y - params.gravity * dt,
29→  }
30→
31→  const newPosition: Vector2D = {
32→    x: state.position.x + state.velocity.x * dt + 0.5 * 0 * dt * dt,
33→    y: state.position.y + state.velocity.y * dt - 0.5 * params.gravity * dt * dt,
34→  }
35→
36→  // Check if projectile has hit the ground
37→  const landed = newPosition.y < 0 && state.position.y >= 0
38→
39→  if (landed) {
40→    // Interpolate to find exact landing position
41→    const tGround = state.position.y / (state.position.y - newPosition.y)
42→    const landX = state.position.x + state.velocity.x * dt * tGround
43→    const landPoint: Vector2D = { x: landX, y: 0 }
44→    return {
45→      position: landPoint,
46→      velocity: { x: 0, y: 0 },
47→      acceleration: { x: 0, y: 0 },
48→      trajectory: [...state.trajectory, landPoint],
49→      landed: true,
50→    }
51→  }
52→
53→  const clampedPosition: Vector2D = {
54→    x: newPosition.x,
55→    y: Math.max(0, newPosition.y),
56→  }
57→
58→  return {
59→    position: clampedPosition,
60→    velocity: newVelocity,
61→    acceleration: { x: 0, y: -params.gravity },
62→    trajectory: [...state.trajectory, { ...clampedPosition }],
63→    landed: false,
64→  }
65→}
66→
67→export const getProjectileStats = (params: ProjectileParams) => {
68→  const angleRad = params.angle * DEG_TO_RAD
69→  const v0 = params.initialVelocity
70→  const g = params.gravity
71→  const maxHeight = (v0 * Math.sin(angleRad)) ** 2 / (2 * g)
72→  const range = (v0 ** 2 * Math.sin(2 * angleRad)) / g
73→  const flightTime = (2 * v0 * Math.sin(angleRad)) / g
74→  return { maxHeight, range, flightTime }
75→}
