const renderEnergyBar = (
  label: string,
  kinetic: number,
  potential: number,
  total: number,
) => {
  const kPct = total > 0 ? (kinetic / total) * 100 : 50
  const pPct = total > 0 ? (potential / total) * 100 : 50
  return h(
    'div',
    { style: 'margin-bottom:12px' },
    h(
      'div',
      { style: 'display:flex;justify-content:space-between;font-size:11px;color:#6c757d;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px;font-weight:600' },
